// ============================================================
// FONCTION PRINCIPALE
// ============================================================

async function main() {
  console.log("\n🌱 DÉMARRAGE DU SEEDING...\n");

  let created = 0;
  let updated = 0;
  let errors = 0;

  // 1. Créer les utilisateurs
  console.log("👤 Création des utilisateurs...");
  for (const user of users) {
    try {
      const existing = await prisma.user.findUnique({
        where: { email: user.email },
      });
      if (!existing) {
        await prisma.user.create({
          data: user,
        });
        console.log(`  ✅ ${user.email} créé`);
      } else {
        console.log(`  ⚠️ ${user.email} existe déjà`);
      }
    } catch (e) {
      console.error(`  ❌ Erreur ${user.email}:`, e.message);
    }
  }

  // 2. Créer les entreprises
  console.log("\n🏢 Création des entreprises...");
  for (const enterprise of enterprises) {
    try {
      const existing = await prisma.entreprise.findUnique({
        where: { referenceSPI: enterprise.referenceSPI },
      });

      if (!existing) {
        await prisma.entreprise.create({
          data: enterprise,
        });
        created++;
      } else {
        await prisma.entreprise.update({
          where: { referenceSPI: enterprise.referenceSPI },
          data: enterprise,
        });
        updated++;
      }
    } catch (e) {
      console.error(`  ❌ Erreur ${enterprise.referenceSPI}:`, e.message);
      errors++;
    }
  }

  console.log("\n📊 RÉSULTAT DU SEEDING :");
  console.log(`   ✅ Créées : ${created}`);
  console.log(`   🔄 Mises à jour : ${updated}`);
  console.log(`   ❌ Erreurs : ${errors}`);
  console.log(`   📈 Total traité : ${created + updated + errors}`);
  console.log("\n🎉 Seeding terminé !\n");
}

main()
  .catch((e) => {
    console.error("❌ Erreur fatale :", e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
